<div id="pref-popup"><button id="pref-close" onclick="document.getElementById('pref-popup').remove()">&times;</button><h3>Welcome</h3><p>Customize your experience</p><form onsubmit="submitPref(event)"><div class="pref-control"><label>Email (Enter your email to continue without re-entering preferences)</label><input type="email" id="pref-email" required /></div><button type="button" id="pref-check" onclick="checkEmail()" class="btn btn-secondary" style="width:100%; margin-bottom:1rem;">Continue with Email</button><div id="pref-details" style="display:none"><div class="pref-control"><label>Name</label><input type="text" id="pref-name" /></div><div class="pref-control"><label>Gender</label><label style="display:inline; margin-right:15px"><input type="radio" name="pref-gender" value="Male" style="width:auto"> Male</label><label style="display:inline"><input type="radio" name="pref-gender" value="Female" style="width:auto"> Female</label></div><div class="pref-control"><label>Select your stream preference according to your carrier dream</label><select id="pref-stream"><option value="">-- Select --</option><option value="Physical Science">Physical Science</option><option value="Biological Science">Biological Science</option><option value="Commerce">Commerce</option><option value="Arts">Arts</option><option value="Engineering Technology">Engineering Technology</option><option value="Biosystems Technology">Biosystems Technology</option></select></div><div class="pref-control"><label>Select preferred university</label><select id="pref-uni" onchange="loadDegrees()"><option value="">-- Select University --</option><?php foreach($unis as $u) echo "<option value=\"" . htmlspecialchars($u) . "\">" . htmlspecialchars($u) . "</option>"; ?></select></div><div class="pref-control"><label>Select your preferred degree</label><input type="text" id="pref-degree" list="degree-list" placeholder="Type to search degrees..." /><datalist id="degree-list"></datalist></div><button type="submit" class="btn btn-primary" style="width:100%">Submit & Continue</button></div></form></div><script>async function checkEmail(){const e=document.getElementById("pref-email").value;if(!e)return alert("Enter email");document.getElementById("pref-check").disabled=true;const fd=new FormData();fd.append("email",e);const r=await fetch("api_preferences.php",{method:"POST",body:fd});const d=await r.json();if(d.success&&d.found){document.getElementById("pref-popup").remove();location.reload();}else{document.getElementById("pref-check").style.display="none";document.getElementById("pref-details").style.display="block";document.getElementById("pref-name").focus();}}async function loadDegrees(){const u=document.getElementById("pref-uni").value;const l=document.getElementById("degree-list");const i=document.getElementById("pref-degree");l.innerHTML="";i.value="";if(!u)return;const r=await fetch("api_preferences.php?action=get_degrees&university="+encodeURIComponent(u));const ds=await r.json();ds.forEach(d=>{const o=document.createElement("option");o.value=d;l.appendChild(o);});}async function submitPref(e){e.preventDefault();const em=document.getElementById("pref-email").value;const nm=document.getElementById("pref-name").value;const gEl=document.querySelector("input[name=pref-gender]:checked");const gnd=gEl?gEl.value:"";const st=document.getElementById("pref-stream").value;const u=document.getElementById("pref-uni").value;const dg=document.getElementById("pref-degree").value;if(!nm||!gnd||!st||!u||!dg)return alert("Fill all fields");const fd=new FormData();fd.append("email",em);fd.append("name",nm);fd.append("gender",gnd);fd.append("stream",st);fd.append("university",u);fd.append("degree",dg);const r=await fetch("api_preferences.php",{method:"POST",body:fd});const d=await r.json();if(d.success){location.reload();}else{alert("Error: "+(d.error||"Unknown"));}}</script>
